import React, { useEffect, useMemo, useState } from "react"
import "./style.scss"
import { Empty, message } from "antd"
import AssociationService from "src/services/AssociationService"
import { useSelector } from "react-redux"
import { getListComboByKey } from "src/lib/utils"
import { SYSTEM_KEY } from "src/constants/constants"
import TitleAndFilter from "./components/TitleAndFIlter"
import ROUTER from "src/router/ROUTER"
import { useNavigate } from "react-router-dom"
import ButtonCustom from "src/components/MyButton/Button"
import MemberService from "src/services/MemberService"
import { Modal } from "antd"
import notice from "src/components/Notice"
const GroupList = () => {
  const [associations, setAssociations] = useState([])
  const [loading, setLoading] = useState(false)
  const navigate = useNavigate()
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [statusFilter, setStatusFilter] = useState(null)
  const [searchKeyword, setSearchKeyword] = useState("")
  const statusList = useMemo(
    () => getListComboByKey(SYSTEM_KEY.ASSOCIATION_STATUS, listSystemKey) || [],
    [listSystemKey],
  )
  const getAssociationList = async () => {
    try {
      setLoading(true)
      const response = await AssociationService.getAssociationListNoAuthor()
      const list = response?.Object ?? []

      const filteredList = Array.isArray(list)
        ? list.filter(item => ![2, 4, 5].includes(item.Status))
        : []
      setAssociations(filteredList)
    } catch (error) {
      console.error("Lỗi khi getAssociationListNoAuthor:", error)
      setAssociations([])
    } finally {
      setLoading(false)
    }
  }

  const handleJoinAssociation = async AssociationID => {
    try {
      const body = { AssociationID }
      const response = await MemberService.joinAssociationRequest(body)

      if (response?.isError) return
      notice({
        msg: "Đăng ký thành công. Vui lòng chờ xác thực từ quản trị viên.",
      })
      getAssociationList()
    } catch (error) {
      console.error("Lỗi khi đăng ký hội nhóm:", error)
      message.error("Có lỗi xảy ra, vui lòng thử lại sau.")
    }
  }

  const confirmJoinAssociation = AssociationID => {
    Modal.confirm({
      title: "Xác nhận đăng ký hội nhóm",
      content: "Bạn có chắc chắn muốn đăng ký tham gia hội nhóm này?",
      okText: "Đăng ký",
      cancelText: "Hủy",
      onOk: () => handleJoinAssociation(AssociationID),
    })
  }

  useEffect(() => {
    getAssociationList()
  }, [])
  const handleFilterStatus = value => {
    if (!value || value === 0) {
      setStatusFilter(null)
    } else {
      setStatusFilter(value)
    }
  }
  const handleSearch = value => {
    setSearchKeyword(value?.trim()?.toLowerCase() || "")
  }
  return (
    <div className="group-list">
      <div className="page-background">
        <TitleAndFilter
          onStatusChange={handleFilterStatus}
          onSearch={handleSearch}
        />
        <div className="mt-20">
          {loading ? (
            <div style={{ textAlign: "center", padding: 40 }}></div>
          ) : associations.length > 0 ? (
            <div className="card-list">
              {associations
                .filter(item => {
                  const isSubAssociation =
                    item.ParentID &&
                    item.ParentID !== "00000000-0000-0000-0000-000000000000"
                  const matchStatus =
                    statusFilter === null || item.Status === statusFilter
                  const matchKeyword =
                    searchKeyword === "" ||
                    item.AssociationName?.toLowerCase().includes(
                      searchKeyword,
                    ) ||
                    item.AssociationCode?.toLowerCase().includes(
                      searchKeyword,
                    ) ||
                    item.Address?.toLowerCase().includes(searchKeyword)
                  return isSubAssociation && matchStatus && matchKeyword
                })
                .map(item => {
                  const matched = statusList.find(
                    i => i.CodeValue === item.Status,
                  )
                  const statusLabel = matched
                    ? matched.Description
                    : "Không xác định"

                  return (
                    <div key={item.AssociationID} className="card">
                      <div
                        onClick={() =>
                          navigate(ROUTER.HOI_NHOM_CHI_TIET(item.AssociationID))
                        }
                      >
                        {item.Image ? (
                          <img
                            className="card-img"
                            src={item.Image}
                            alt={item.AssociationName}
                          />
                        ) : (
                          <img
                            src="src/assets/images/logo/logo_mac_dinh.png"
                            className="card-img"
                          />
                        )}
                      </div>

                      <div className="card-body">
                        <div className="card-header">
                          <h3
                            className="card-title"
                            style={{ cursor: "pointer" }}
                          >
                            {item.AssociationName}
                          </h3>
                          <span className="card-role">{statusLabel}</span>
                        </div>
                        <div className="d-flex-sb">
                          <p className="card-description">
                            Số hội viên: {item.MemberNo}
                          </p>
                          <ButtonCustom
                            onClick={() =>
                              confirmJoinAssociation(item.AssociationID)
                            }
                          >
                            Đăng ký
                          </ButtonCustom>
                        </div>
                      </div>
                    </div>
                  )
                })}
            </div>
          ) : (
            <div style={{ textAlign: "center", padding: 40 }}>
              <Empty description="Không có hội nhóm nào" />
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

export default GroupList
