import { Row, Col, Select, Input } from "antd"
import TitleCustom from "src/components/TitleCustom"
import { useSelector } from "react-redux"
import { useMemo } from "react"
import { getListComboByKey } from "src/lib/utils"
import { SYSTEM_KEY } from "src/constants/constants"
import SelectCustom from "src/components/Select/SelectCustom"

const { Option } = Select

const TitleAndFilter = ({ onStatusChange, onSearch }) => {
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const statusList = useMemo(() => {
    const list =
      getListComboByKey(SYSTEM_KEY.ASSOCIATION_STATUS, listSystemKey) || []

    const filteredList = list.filter(
      item => ![2, 4, 5].includes(item.CodeValue),
    )

    return [{ CodeValue: 0, Description: "Tất cả" }, ...filteredList]
  }, [listSystemKey])
  return (
    <Row gutter={[16, 16]} align="middle">
      <Col span={6}>
        <TitleCustom>Danh Sách Hội Nhóm</TitleCustom>
      </Col>

      <Col span={6}>
        <SelectCustom
          style={{ width: "100%" }}
          placeholder="Lọc theo trạng thái"
          onChange={onStatusChange}
          allowClear
        >
          {statusList.map(item => (
            <Option key={item.Codekey} value={item.CodeValue}>
              {item.Description}
            </Option>
          ))}
        </SelectCustom>
      </Col>

      <Col span={12}>
        <Input.Search
          placeholder="Tìm kiếm theo tên hội"
          onSearch={onSearch}
          enterButton
          allowClear
        />
      </Col>
    </Row>
  )
}

export default TitleAndFilter
